={
  "model": "qwen3:1.7b",
  "temperature": 0.1,
  "system": "You are an intent classifier. Respond ONLY with compact JSON, no markdown, no explanations. Categories: TASK = create/update/query a task, reminder, to-do or calendar event, including where to store it (Notion, Trello, etc.). Examples: 'add this to my calendar', 'guarda el task en Notion', 'recuerdame llamar al banco'. NOTE = create or query a note. Examples: 'quiero tomar nota de esto', 'apunta que...', 'save this as a note'. CONTENT = draft or publish a post or article. PROGRESS = log metrics or progress. TECHNICAL_QUERY = complex technical/engineering questions that need deep reasoning. SIMPLE_QUERY = short general questions. CHAT = greetings and casual conversation. Examples: 'hola', 'how are you'. Rules: use_claude=true ONLY for TECHNICAL_QUERY. For CHAT and SIMPLE_QUERY always use_claude=false. Output format: {\"intent\":\"CATEGORY\",\"confidence\":0.0-1.0,\"use_claude\":true|false}",
  "prompt": "{{ $json.raw_text }}"
}

parameters.jsCode:
const fast = $('Fast route').first().json;
let intent, confidence, use_claude, route;

if (fast._decided) {
  route = fast.route; intent = fast.intent; confidence = fast.confidence; use_claude = fast.use_claude;
} else {
  let parsed;
  try {
    let raw = $input.first().json.result || '{}';
    raw = raw.replace(/<think>[\s\S]*?<\/think>/g, '');   // qwen3 reasoning block
    const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    parsed = JSON.parse(match ? match[0] : cleaned);
  } catch (e) {
    parsed = { intent: 'CHAT', confidence: 0.5, use_claude: false };
  }
  intent = parsed.intent || 'CHAT';
  confidence = parsed.confidence ?? 0.5;
  use_claude = !!parsed.use_claude;
  // Casual conversation must always stay on local Qwen.
  if (intent === 'CHAT' || intent === 'SIMPLE_QUERY') use_claude = false;
  const KNOWN = ['TASK','NOTE','CONTENT','PROGRESS','CHAT','SIMPLE_QUERY'];
  route = use_claude ? 'CLAUDE' : intent;
  if (route !== 'CLAUDE' && !KNOWN.includes(route)) route = 'CHAT';
}

return [{ json: {
  raw_text: fast.raw_text,
  chat_id: fast.chat_id,
  username: fast.username,
  timestamp: fast.timestamp,
  intent, confidence, use_claude, route,
  tasks: fast.tasks || null
} }];

