const all = $input.all();
const r = all.find(i => i.json.response_text) || all[0];
const d = $('Parse intent').first().json;
const src = r.json.source || 'System';
const icon = src === 'Claude' ? '🤖' : src.includes('Ollama') ? '⚡' : '🔧';
return [{
  json: {
    chat_id: d.chat_id,
    response_text: r.json.response_text,
    footer: `\n\n${icon} ${src} · ${d.intent} (${Math.round((d.confidence||0)*100)}%)`
  }
}];

const d = $input.first().json;
let text = (d.raw_text || '').trim();
const lower = text.toLowerCase();
const chatKey = String(d.chat_id);

// ── Pending /plan confirmation state (persisted in workflow static data) ──────
const staticData = $getWorkflowStaticData('global');
staticData.pendingPlans = staticData.pendingPlans || {};
const pending = staticData.pendingPlans[chatKey];

function emit(route, intent, extra) {
  return [{ json: Object.assign({
    raw_text: text,
    chat_id: d.chat_id,
    username: d.username,
    timestamp: d.timestamp,
    _decided: true,
    route: route,
    intent: intent,
    confidence: 1,
    use_claude: route === 'CLAUDE'
  }, extra || {}) }];
}

if (pending && Array.isArray(pending.tasks) && pending.tasks.length) {
  const confirmRe = /^(ok(ey|ay)?|oka|s[ií]|vale|listo|dale|yes|yep|confirm(ar)?|crear|create|hazlo|adelante)(?=$|[\s,.!;:])/i;
  const cancelRe  = /^(no|cancel(ar|a)?|descartar?|olv[ií]dalo|nada)(?=$|[\s,.!;:])/i;
  const nums = (text.match(/\d+/g) || []).map(function (n) { return parseInt(n, 10); });
  const onlyNums = /^[\s\d,.]+$/.test(text) && nums.length > 0;

  if (cancelRe.test(text)) {
    return emit('PLAN_CANCEL', 'PLAN_CANCEL');
  }
  if (confirmRe.test(text) || onlyNums) {
    let tasks = pending.tasks;
    if (nums.length) tasks = nums.map(function (i) { return pending.tasks[i - 1]; }).filter(Boolean);
    if (!tasks.length) tasks = pending.tasks;
    return emit('PLAN_CONFIRM', 'PLAN_CONFIRM', { tasks: tasks });
  }
  // Any other message abandons the pending plan and is routed normally.
  delete staticData.pendingPlans[chatKey];
}

// ── Slash commands go straight to an agent (skip the qwen classifier) ─────────
const SLASH = { '/claude':'CLAUDE', '/task':'TASK', '/note':'NOTE', '/content':'CONTENT', '/progress':'PROGRESS', '/qwen':'CHAT', '/chat':'CHAT', '/plan':'PLAN' };
let decided = false, route = null;
const m = lower.match(/^(\/[a-z]+)\b/);
if (m && SLASH[m[1]]) {
  route = SLASH[m[1]];
  decided = true;
  text = text.slice(m[1].length).trim();   // strip the command token
}

// Very large prompts go straight to Claude (skip classification).
const MAX_LOCAL_CHARS = 1500;
if (!decided && text.length > MAX_LOCAL_CHARS) { route = 'CLAUDE'; decided = true; }

const intent = route === 'CLAUDE' ? 'TECHNICAL_QUERY' : (route || 'CHAT');
return [{
  json: {
    raw_text: text,
    chat_id: d.chat_id,
    username: d.username,
    timestamp: d.timestamp,
    _decided: decided,
    route: decided ? route : null,
    intent: decided ? intent : null,
    confidence: decided ? 1 : null,
    use_claude: decided ? (route === 'CLAUDE') : false
  }
}];

// Turn the incoming message into a note payload for Hermes note_save.
const d = $('Parse intent').first().json;
const text = (d.raw_text || '').trim();
const nl = text.indexOf('\n');
const title = (nl === -1 ? text : text.slice(0, nl)).slice(0, 120) || 'Quick note';
const body = { title, content: text, folder: 'Inbox', tags: ['cerebro'], sync: true };
return [{ json: { requestBody: JSON.stringify(body) } }];

const r = $input.first().json;
const text = r.ok ? `📝 ${r.result}` : `⚠️ Note not saved: ${r.error || 'unknown error'}`;
return [{ json: { response_text: text, source: 'Brain' } }];

// Build a Linear GraphQL mutation from the incoming message.
// First line -> issue title, the rest -> description.
const d = $('Parse intent').first().json;
const text = (d.raw_text || '').trim();
const nl = text.indexOf('\n');
const title = (nl === -1 ? text : text.slice(0, nl)).slice(0, 200) || 'Untitled task';
const description = nl === -1 ? '' : text.slice(nl + 1).trim();
// TODO: set your Linear team id (see setup instructions).
const teamId = 'REPLACE_WITH_LINEAR_TEAM_ID';
const body = {
  query: 'mutation CreateIssue($teamId: String!, $title: String!, $description: String) { issueCreate(input: { teamId: $teamId, title: $title, description: $description }) { success issue { identifier title url } } }',
  variables: { teamId, title, description },
};
return [{ json: { requestBody: JSON.stringify(body) } }];

const r = $input.first().json;
const res = r && r.data && r.data.issueCreate;
const issue = res && res.issue;
const text = (res && res.success && issue)
  ? `✅ Task created in Linear: ${issue.identifier} — ${issue.title}\n${issue.url}`
  : `⚠️ Could not create the Linear task.\n${JSON.stringify((r && r.errors) || r).slice(0, 400)}`;
return [{ json: { response_text: text, source: 'Linear' } }];

// Ask the LLM to extract a JSON array of tasks from the plan text.
const d = $('Parse intent').first().json;
const text = (d.raw_text || '').trim();
const system = [
  'You are a task-extraction assistant.',
  'From the user message, extract the concrete, actionable tasks it implies.',
  'Return ONLY a JSON array, with no markdown fences and no prose.',
  'Each element must be an object: {"title": string (imperative, max 120 chars), "description": string (optional context, may be empty)}.',
  'Split compound sentences into separate tasks. Ignore greetings and filler.',
  'Keep each task in the same language as the user. If there are no actionable tasks, return [].'
].join(' ');
const body = { system: system, prompt: text, max_tokens: 1024, temperature: 0.2 };
return [{ json: { requestBody: JSON.stringify(body) } }];

// Parse the extracted tasks, stash them as a pending plan, and show a preview.
const d = $('Parse intent').first().json;
const chatKey = String(d.chat_id);
let raw = $input.first().json.result || '';
raw = raw.replace(/<think>[\s\S]*?<\/think>/g, '');
raw = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();

let tasks = [];
try {
  const match = raw.match(/\[[\s\S]*\]/);
  const arr = JSON.parse(match ? match[0] : raw);
  if (Array.isArray(arr)) {
    tasks = arr
      .map(function (t) { return typeof t === 'string' ? { title: t, description: '' } : t; })
      .filter(function (t) { return t && t.title; })
      .map(function (t) { return { title: String(t.title).slice(0, 200), description: String(t.description || '') }; });
  }
} catch (e) { tasks = []; }

if (!tasks.length) {
  return [{ json: {
    response_text: '🧐 No pude extraer tareas claras de ese texto. Intenta describir con un poco más de detalle lo que hay que hacer.',
    source: 'Plan'
  } }];
}

const staticData = $getWorkflowStaticData('global');
staticData.pendingPlans = staticData.pendingPlans || {};
staticData.pendingPlans[chatKey] = { tasks: tasks, createdAt: new Date().toISOString() };

const list = tasks.map(function (t, i) {
  return (i + 1) + '. ' + t.title + (t.description ? ' — ' + t.description : '');
}).join('\n');
const response_text = '📋 Detecté ' + tasks.length + ' tarea(s):\n\n' + list +
  '\n\nResponde OK para crearlas en Linear, cancelar para descartar, o los números (ej. 1,3) para crear solo esas.';
return [{ json: { response_text: response_text, source: 'Plan' } }];

// One Linear issue per confirmed task (emits one item per task).
const d = $('Parse intent').first().json;
const tasks = Array.isArray(d.tasks) ? d.tasks : [];
// TODO: must match the team UUID set in the "Build task" node.
const LINEAR_TEAM_ID = 'REPLACE_WITH_LINEAR_TEAM_UUID';
const query = 'mutation CreateIssue($teamId: String!, $title: String!, $description: String) { issueCreate(input: { teamId: $teamId, title: $title, description: $description }) { success issue { identifier title url } } }';
if (!tasks.length) {
  return [{ json: { _empty: true, requestBody: null } }];
}
return tasks.map(function (t) {
  return { json: {
    title: t.title,
    requestBody: JSON.stringify({
      query: query,
      variables: { teamId: LINEAR_TEAM_ID, title: String(t.title).slice(0, 200), description: String(t.description || '') }
    })
  } };
});

// Aggregate the per-issue responses into one Telegram message; clear state.
const items = $input.all();
const d = $('Parse intent').first().json;
const chatKey = String(d.chat_id);
const lines = [];
let ok = 0;
for (const it of items) {
  const r = it.json || {};
  const res = r.data && r.data.issueCreate;
  const issue = res && res.issue;
  if (res && res.success && issue) {
    ok++;
    lines.push('✅ ' + issue.identifier + ' — ' + issue.title + '\n' + issue.url);
  } else {
    const err = JSON.stringify(r.errors || r).slice(0, 200);
    lines.push('⚠️ Falló una tarea: ' + err);
  }
}
const staticData = $getWorkflowStaticData('global');
if (staticData.pendingPlans) delete staticData.pendingPlans[chatKey];
const response_text = '📌 Creé ' + ok + '/' + items.length + ' tarea(s) en Linear:\n\n' + lines.join('\n\n');
return [{ json: { response_text: response_text, source: 'Linear' } }];

const d = $('Parse intent').first().json;
const chatKey = String(d.chat_id);
const staticData = $getWorkflowStaticData('global');
if (staticData.pendingPlans) delete staticData.pendingPlans[chatKey];
return [{ json: { response_text: '🚫 Plan descartado. No creé ninguna tarea.', source: 'Plan' } }];
